const delivery = $input.first().json;

// Calculate metrics
const promisedDate = new Date(delivery.promisedDeliveryDate);
const actualDate = new Date(delivery.actualDeliveryDate);
const onTime = actualDate <= promisedDate;

const hoursLate = onTime ? 0 : (actualDate - promisedDate) / (1000 * 60 * 60);

// Damage check
const damaged = delivery.damageReported || false;

// Cost per mile
const costPerMile = delivery.totalCost / delivery.miles;

return {
  carrierId: delivery.carrierId,
  shipmentId: delivery.shipmentId,
  onTime,
  hoursLate,
  damaged,
  costPerMile,
  route: delivery.origin + ' → ' + delivery.destination,
  date: delivery.actualDeliveryDate
};

// Simulate rolling score calculation
// In production, query last 30 days from sheet
const carrierId = $input.first().json.carrierId;

// Mock calculation (replace with actual aggregation)
const mockScore = {
  onTimeRate: 0.92,  // 92%
  damageRate: 0.02,   // 2%
  avgCostPerMile: 2.15,
  totalShipments: 45,
  carrierId: carrierId
};

// Determine status
let status = 'Good';
if (mockScore.onTimeRate < 0.85) status = 'At Risk';
if (mockScore.onTimeRate < 0.75) status = 'Critical';
if (mockScore.onTimeRate > 0.95 && mockScore.damageRate < 0.01) status = 'Preferred';

return { ...mockScore, status };

